## Interface Contracts
### types/meal.ts (typescript_interface)
Core meal data types including Meal, MealCategory, MealFilter, and MealWithMatch for the entire application
```python
export type MealCategory = 'breakfast' | 'lunch' | 'dinner' | 'snack';

export interface Meal {
  id: string;
  name: string;
  imageUrl: string;
  description: string;
  ingredients: string[];
  instructions: string[];
  category: MealCategory;
  prepTime?: number;
  difficulty?: 'easy' | 'medium' | 'hard';
}

export interface MealWithMatch extends Meal {
  matchPercentage: number;
}

export interface MealFilter {
  category?: MealCategory;
  ingredients?: string[];
  difficulty?: 'easy' | 'medium' | 'hard';
  prepTime?: number;
}

export interface MealSortOption {
  type: 'match' | 'random' | 'category';
  direction?: 'asc' | 'desc';
}

```

