import { IIngredientUtils } from '@/types/utils';

export const ingredientUtils: IIngredientUtils = {
  normalizeIngredient(ingredient: string): string {
    return ingredient.toLowerCase().trim().replace(/\s+/g, ' ');
  },

  normalizeIngredients(ingredients: string[]): string[] {
    const normalized = ingredients.map(ing => this.normalizeIngredient(ing));
    return Array.from(new Set(normalized)).filter(Boolean);
  },

  ingredientsMatch(ingredient1: string, ingredient2: string): boolean {
    const norm1 = this.normalizeIngredient(ingredient1);
    const norm2 = this.normalizeIngredient(ingredient2);
    return norm1 === norm2 || norm1.includes(norm2) || norm2.includes(norm1);
  },

  getSuggestions(input: string, allIngredients: string[], limit = 10): string[] {
    if (!input.trim()) return [];

    const normalizedInput = this.normalizeIngredient(input);
    const suggestions = allIngredients.filter(ing =>
      this.normalizeIngredient(ing).includes(normalizedInput)
    );

    return suggestions.slice(0, limit);
  }
};
