import { Meal, MealCategory, MealFilter, MealWithMatch } from '@/types/meal';
import { IMealService } from '@/types/services';
import { ingredientUtils } from '@/utils/ingredientUtils';
import mealsData from '@/data/meals.json';

class MealService implements IMealService {
  private meals: Meal[] = [];

  async loadMeals(): Promise<Meal[]> {
    if (this.meals.length === 0) {
      this.meals = mealsData as Meal[];
    }
    return this.meals;
  }

  getMealById(id: string, meals: Meal[]): Meal | undefined {
    return meals.find(meal => meal.id === id);
  }

  getRandomMeal(meals: Meal[], excludeId?: string): Meal {
    const availableMeals = excludeId
      ? meals.filter(meal => meal.id !== excludeId)
      : meals;

    if (availableMeals.length === 0) {
      return meals[Math.floor(Math.random() * meals.length)];
    }

    return availableMeals[Math.floor(Math.random() * availableMeals.length)];
  }

  filterMeals(meals: Meal[], filter: MealFilter): Meal[] {
    let filtered = [...meals];

    if (filter.category) {
      filtered = filtered.filter(meal => meal.category === filter.category);
    }

    if (filter.difficulty) {
      filtered = filtered.filter(meal => meal.difficulty === filter.difficulty);
    }

    if (filter.prepTime) {
      filtered = filtered.filter(meal =>
        meal.prepTime && meal.prepTime <= filter.prepTime!
      );
    }

    if (filter.ingredients && filter.ingredients.length > 0) {
      filtered = this.findMealsByIngredients(filtered, filter.ingredients)
        .filter(meal => meal.matchPercentage > 0)
        .map(({ matchPercentage, ...meal }) => meal);
    }

    return filtered;
  }

  calculateMatchPercentage(mealIngredients: string[], userIngredients: string[]): number {
    if (mealIngredients.length === 0) return 0;

    const normalizedMealIngs = ingredientUtils.normalizeIngredients(mealIngredients);
    const normalizedUserIngs = ingredientUtils.normalizeIngredients(userIngredients);

    let matchCount = 0;
    for (const mealIng of normalizedMealIngs) {
      for (const userIng of normalizedUserIngs) {
        if (ingredientUtils.ingredientsMatch(mealIng, userIng)) {
          matchCount++;
          break;
        }
      }
    }

    return Math.round((matchCount / normalizedMealIngs.length) * 100);
  }

  findMealsByIngredients(meals: Meal[], userIngredients: string[]): MealWithMatch[] {
    if (userIngredients.length === 0) return [];

    const mealsWithMatch: MealWithMatch[] = meals.map(meal => ({
      ...meal,
      matchPercentage: this.calculateMatchPercentage(meal.ingredients, userIngredients)
    }));

    return mealsWithMatch
      .filter(meal => meal.matchPercentage > 0)
      .sort((a, b) => b.matchPercentage - a.matchPercentage);
  }

  getAllIngredients(meals: Meal[]): string[] {
    const allIngredients = new Set<string>();
    meals.forEach(meal => {
      meal.ingredients.forEach(ing => {
        allIngredients.add(ingredientUtils.normalizeIngredient(ing));
      });
    });
    return Array.from(allIngredients).sort();
  }

  getMealsByCategory(meals: Meal[], category: MealCategory): Meal[] {
    return meals.filter(meal => meal.category === category);
  }
}

export const mealService = new MealService();
