import { supabase } from './client';
import { Meal } from '@/types/meal';
import { ISupabaseMealService } from '@/types/services';

class SupabaseMealService implements ISupabaseMealService {
  async getMeals(): Promise<Meal[]> {
    const { data, error } = await supabase
      .from('meals')
      .select('*')
      .order('name');

    if (error) throw error;

    return (data || []).map(this.mapDbMealToMeal);
  }

  async createMeal(meal: Omit<Meal, 'id'>): Promise<Meal> {
    const { data, error } = await supabase
      .from('meals')
      .insert(this.mapMealToDbMeal(meal))
      .select()
      .single();

    if (error) throw error;
    return this.mapDbMealToMeal(data);
  }

  async updateMeal(id: string, meal: Partial<Meal>): Promise<Meal> {
    const { data, error } = await supabase
      .from('meals')
      .update(this.mapMealToDbMeal(meal as Meal))
      .eq('id', id)
      .select()
      .single();

    if (error) throw error;
    return this.mapDbMealToMeal(data);
  }

  async deleteMeal(id: string): Promise<void> {
    const { error } = await supabase
      .from('meals')
      .delete()
      .eq('id', id);

    if (error) throw error;
  }

  async bulkImportMeals(meals: Meal[]): Promise<Meal[]> {
    const dbMeals = meals.map(this.mapMealToDbMeal);

    const { data, error } = await supabase
      .from('meals')
      .insert(dbMeals)
      .select();

    if (error) throw error;
    return (data || []).map(this.mapDbMealToMeal);
  }

  private mapDbMealToMeal(dbMeal: any): Meal {
