    mutationFn: (mealId: string) => favoritesService.addFavorite(user!.id, mealId),
    onSuccess: (_, mealId) => {
      addFavorite(mealId);
      queryClient.invalidateQueries(['favorites', user?.id]);
    },
  });

  // Remove favorite
  const removeMutation = useMutation({
    mutationFn: (mealId: string) => favoritesService.removeFavorite(user!.id, mealId),
    onSuccess: (_, mealId) => {
      removeFavorite(mealId);
      queryClient.invalidateQueries(['favorites', user?.id]);
    },
  });

  return {
    favorites,
    isLoading,
    addFavorite: addMutation.mutate,
    removeFavorite: removeMutation.mutate,
    isFavorite: (mealId: string) => favorites.includes(mealId),
  };
}
