import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { historyService } from '@/services/supabase';
import { useAppStore } from '@/stores/useAppStore';

export function useHistory() {
  const { user, history, setHistory, addToHistory } = useAppStore();
  const queryClient = useQueryClient();

  // Get history
  const { data, isLoading } = useQuery({
    queryKey: ['history', user?.id],
    queryFn: () => historyService.getHistory(user!.id),
    enabled: !!user,
    onSuccess: (data) => {
      setHistory(data.map(h => h.meal_id));
    },
  });

  // Add to history
  const addMutation = useMutation({
    mutationFn: (mealId: string) => historyService.addToHistory(user!.id, mealId),
    onSuccess: (_, mealId) => {
      addToHistory(mealId);
      queryClient.invalidateQueries(['history', user?.id]);
    },
  });

  return {
    history,
    historyData: data || [],
    isLoading,
    addToHistory: addMutation.mutate,
  };
}
