import { MatchIndicatorProps } from '@/types/components';
import { motion } from 'framer-motion';

export function MatchIndicator({ percentage, size = 'md' }: MatchIndicatorProps) {
  const sizes = {
    sm: 'w-12 h-12 text-xs',
    md: 'w-16 h-16 text-sm',
    lg: 'w-20 h-20 text-base',
  };

  const getColor = () => {
    if (percentage >= 80) return 'from-green-500 to-green-600';
    if (percentage >= 50) return 'from-yellow-500 to-yellow-600';
    return 'from-orange-500 to-orange-600';
  };

  return (
    <motion.div
      initial={{ scale: 0 }}
      animate={{ scale: 1 }}
      className={`${sizes[size]} rounded-full bg-gradient-to-br ${getColor()} flex items-center justify-center text-white font-bold shadow-lg`}
    >
      {percentage}%
    </motion.div>
  );
}
